const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let plugins = [];

if (process.env.PLUGINS) {
  const pluginCodes = process.env.PLUGINS.split(',');
  for (const code of pluginCodes) {
    try {
      const plugin = eval(code);
      if (plugin && plugin.init) {
        plugin.init(app, plugins);
        plugins.push(plugin);
      }
    } catch (e) {
      console.error(`Error loading plugin: ${code}`);
      console.error(e.stack);
    }
  }
}

if (process.env.PLUGINS_FILE) {
  const fs = require('fs');
  try {
    const fileContent = fs.readFileSync(process.env.PLUGINS_FILE, 'utf8');
    const pluginCodes = fileContent.split('\n');
    for (const code of pluginCodes) {
      if (code.trim()) {
        try {
          const plugin = eval(code);
          if (plugin && plugin.init) {
            plugin.init(app, plugins);
            plugins.push(plugin);
          }
        } catch (e) {
          console.error(`Error loading plugin from file: ${process.env.PLUGINS_FILE}`);
          console.error(e.stack);
        }
      }
    }
  } catch (e) {
    console.error(`Error reading plugins file: ${process.env.PLUGINS_FILE}`);
    console.error(e.stack);
  }
}

app.use((req, res, next) => {
  for (const plugin of plugins) {
    if (plugin && plugin.beforeRequest) {
      try {
        const result = plugin.beforeRequest(req, res);
        if (result !== undefined) {
          req = result;
        }
      } catch (e) {
        console.error(`Error executing beforeRequest hook: ${plugin.name}`);
        console.error(e.stack);
      }
    }
  }
  next();
});

app.use((req, res, next) => {
  for (const plugin of plugins) {
    if (plugin && plugin.afterRequest) {
      try {
        const result = plugin.afterRequest(req, res);
        if (result !== undefined) {
          res = result;
        }
      } catch (e) {
        console.error(`Error executing afterRequest hook: ${plugin.name}`);
        console.error(e.stack);
      }
    }
  }
  next();
});

app.use((req, res, next) => {
  for (const plugin of plugins) {
    if (plugin && plugin.execute) {
      try {
        const result = plugin.execute(req, res);
        if (result !== undefined) {
          res = result;
        }
      } catch (e) {
        console.error(`Error executing execute hook: ${plugin.name}`);
        console.error(e.stack);
      }
    }
  }
  next();
});

app.use((err, req, res, next) => {
  for (const plugin of plugins) {
    if (plugin && plugin.onError) {
      try {
        const result = plugin.onError(err, req, res);
        if (result !== undefined) {
          err = result;
        }
      } catch (e) {
        console.error(`Error executing onError hook: ${plugin.name}`);
        console.error(e.stack);
      }
    }
  }
  next(err);
});

app.listen(3000, () => {
  console.log('API Gateway listening on port 3000');
});